1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office - quote (premium)", () => {
5	  // Fee-only baseline
6	  it.todo("should charge 5 G (fee only) for an empty item list");
7	
8	  // Single main item base premiums + fee
9	  it.todo("should quote a single sword at 105 G (100 base + 5 fee)");
10	  it.todo("should quote a single amulet at 65 G (60 base + 5 fee)");
11	  it.todo("should quote a single staff at 85 G (80 base + 5 fee)");
12	  it.todo("should quote a single potion at 45 G (40 base + 5 fee)");
13	
14	  // Multiple main items sum their base premiums
15	  it.todo("should sum base premiums for a sword and an amulet to 165 G (160 base + 5 fee)");
16	
17	  // Component base premiums
18	  it.todo("should quote a single rune at 30 G (25 base + 5 fee)");
19	  it.todo("should quote 2 runes at 55 G (50 base + 5 fee)");
20	
21	  // Building block of 3 alike components
22	  it.todo("should quote 3 runes as a block at 65 G (60 base + 5 fee)");
23	  it.todo("should quote 4 runes at 105 G (no block, 100 base + 5 fee)");
24	  it.todo("should quote 7 runes at 180 G (175 base + 5 fee)");
25	
26	  // Alike = same type only
27	  it.todo("should not form a block for 2 runes + 1 moonstone (75 base + 5 fee = 80 G)");
28	  it.todo("should form two separate blocks for 3 runes + 3 moonstones (120 base + 5 fee = 125 G)");
29	
30	  // Item-specific modifiers
31	  it.todo("should add 50% curse surcharge to the cursed item's base premium");
32	  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
33	  it.todo("should not add high-enchantment surcharge for enchantment 4");
34	  it.todo("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item");
35	
36	  // Modifier scope on multi-item policies
37	  it.todo("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)");
38	
39	  // Policy-wide modifiers
40	  it.todo("should apply 20% loyalty discount for a customer with exactly 2 years");
41	  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
42	  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");
43	
44	  // Rounding up in MHPCO's favor
45	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
46	
47	  // Integration examples
48	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
49	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
50	
51	  // Error case
52	  it.todo("should reject a quote containing an item with an unknown type");
53	});
54	
55	describe("Claim Office - claim (payout)", () => {
56	  // Standard reimbursement minus deductible
57	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
58	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
59	
60	  // High-enchantment clause
61	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
62	
63	  // Dragon-material clause
64	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
65	
66	  // Conflict: 50% rule wins over dragon
67	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
68	
69	  // Threshold confirmation
70	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
71	
72	  // Deductible per damage event
73	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
74	
75	  // Cap behaviour
76	  it.todo("should cap total payout at twice the insurance sum");
77	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
78	
79	  // Rounding down in MHPCO's favor
80	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
81	
82	  // Error cases
83	  it.todo("should reject a claim whose damage entry references an item not in the policy");
84	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
85	  it.todo("should reject a claim with a negative damage amount");
86	});
